const files = $input.all().map(i => i.json);

const sections = files.map((file, index) => ({
  type: 'page',
  align: 'center',
  content: [
    {
      type: 'h1',
      text: file.name.replace(/\.pdf$/i, ''),
      fontSize: 28,
      color: '#1a1a1a'
    },
    {
      type: 'text',
      text: ' '
    },
    {
      type: 'text',
      text: `Created: ${file.createdTime ? new Date(file.createdTime).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }) : 'Unknown'}`,
      fontSize: 14,
      color: '#555555'
    },
    {
      type: 'text',
      text: `Last Modified: ${file.modifiedTime ? new Date(file.modifiedTime).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }) : 'Unknown'}`,
      fontSize: 14,
      color: '#555555'
    },
    {
      type: 'text',
      text: `Owner: ${file.owners && file.owners[0] ? file.owners[0].displayName : 'Unknown'}`,
      fontSize: 14,
      color: '#555555'
    },
    {
      type: 'text',
      text: `Document ${index + 1} of ${files.length}`,
      fontSize: 12,
      color: '#999999'
    }
  ]
}));

const config = {
  document: { type: 'pdf', size: 'A4' },
  sections
};

return [{
  json: {
    config: JSON.stringify(config),
    files: files.map((f, i) => ({ id: f.id, name: f.name, index: i }))
  }
}];

const titlePagesFileId = $input.first().json.id;
const files = $('Build Title Pages JSON').first().json.files;

return files.map((file, index) => ({
  json: {
    driveFileId: file.id,
    fileName: file.name,
    titlePageNumber: index + 1,
    titlePagesFileId
  }
}));

const titlePageFileId = $json.outputFileId
const docFileId = $('Upload Document to Autype').item.json.id;
const fileName = $('Loop Over Documents').item.json.fileName;

return [{
  json: {
    titlePageFileId,
    docFileId,
    fileName
  }
}];

const items = $input.all();
const fileIds = [];

for (const item of items) {
  fileIds.push(item.json.titlePageFileId);
  fileIds.push(item.json.docFileId);
}

return [{ json: { fileIds: fileIds.join(',') } }];
